  ('heelevel3-7c4986e7-moex-00240', 'heelevel3-7c4986e7', 'heelevel3-7c4986e7-moex-111-d3ff7f6b', 'sub-heelevel3-7c4986e7-03', NULL, 'single_choice', '根據梭羅（SolowModel）模型，假設A國和B國的生產函數、人口成長率與資本折舊率都相同， 但A國儲蓄率大於B國。若兩國都沒有技術進步的情況下，則下列敘述何者正確？', '["A國目前的每人平均產出一定大於B國", "A國目前的每人平均產出一定等於B國", "長期時，A國的每人平均產出成長率一定大於B國", "長期時，A國的每人平均產出成長率一定等於B國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:32:26+00:00", "source_pdf_sha1": "7b2be102255d", "answer_pdf_sha1": "40ea3bc8eedf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "322", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "金融保險"}'::jsonb, NULL),
